use serde::{Deserialize, Serialize};
use std::io::{self, Read};

const PI: f64 = 3.1415926535;

#[derive(Debug, Deserialize)]
struct Input {
    numpoints: usize,
    x: Vec<f64>,
    y: Vec<f64>,
    parameters: Parameters,
    lcm: Vec<Vec<String>>,
    pum_diag: Vec<bool>,
}

#[derive(Debug, Deserialize)]
struct Parameters {
    #[serde(rename = "LENGTH1")]
    length1: f64,
    #[serde(rename = "RADIUS1")]
    radius1: f64,
    #[serde(rename = "EPSILON")]
    epsilon: f64,
    #[serde(rename = "AREA1")]
    area1: f64,
    #[serde(rename = "Q_PTS")]
    q_pts: usize,
    #[serde(rename = "QUADS")]
    quads: usize,
    #[serde(rename = "DIST")]
    dist: f64,
    #[serde(rename = "N_PTS")]
    n_pts: usize,
    #[serde(rename = "K_PTS")]
    k_pts: usize,
    #[serde(rename = "A_PTS")]
    a_pts: usize,
    #[serde(rename = "B_PTS")]
    b_pts: usize,
    #[serde(rename = "C_PTS")]
    c_pts: usize,
    #[serde(rename = "D_PTS")]
    d_pts: usize,
    #[serde(rename = "E_PTS")]
    e_pts: usize,
    #[serde(rename = "F_PTS")]
    f_pts: usize,
    #[serde(rename = "G_PTS")]
    g_pts: usize,
    #[serde(rename = "LENGTH2")]
    length2: f64,
    #[serde(rename = "RADIUS2")]
    radius2: f64,
    #[serde(rename = "AREA2")]
    area2: f64,
}

#[derive(Debug, Serialize)]
struct Output {
    cmv: Vec<bool>,
    pum: Vec<Vec<bool>>,
    fuv: Vec<bool>,
    launch: bool,
}

fn realcompare(a: f64, b: f64) -> i32 {
    let scale = a.abs().max(b.abs());
    let eps = if scale == 0.0 { 0.0 } else { 0.5e-5 * scale };
    let diff = a - b;
    if diff > eps {
        1 // GT
    } else if diff < -eps {
        -1 // LT
    } else {
        0 // EQ
    }
}

fn distance(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn angle_at_vertex(p1: (f64, f64), vertex: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    let dx1 = p1.0 - vertex.0;
    let dy1 = p1.1 - vertex.1;
    let dx3 = p3.0 - vertex.0;
    let dy3 = p3.1 - vertex.1;

    if realcompare(dx1, 0.0) == 0 && realcompare(dy1, 0.0) == 0 {
        return None;
    }
    if realcompare(dx3, 0.0) == 0 && realcompare(dy3, 0.0) == 0 {
        return None;
    }

    let dot = dx1 * dx3 + dy1 * dy3;
    let cross = dx1 * dy3 - dy1 * dx3;
    Some(cross.atan2(dot).abs())
}

fn triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    ((p1.0 * (p2.1 - p3.1) + p2.0 * (p3.1 - p1.1) + p3.0 * (p1.1 - p2.1)).abs()) / 2.0
}

fn radius_of_three_points(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> Option<f64> {
    let area = triangle_area(p1, p2, p3);
    if realcompare(area, 0.0) == 0 {
        return None;
    }
    let a = distance(p1.0, p1.1, p2.0, p2.1);
    let b = distance(p2.0, p2.1, p3.0, p3.1);
    let c = distance(p3.0, p3.1, p1.0, p1.1);
    let radius = (a * b * c) / (4.0 * area);
    Some(radius)
}

fn get_quadrant(x: f64, y: f64) -> usize {
    if realcompare(x, 0.0) >= 0 && realcompare(y, 0.0) >= 0 {
        1
    } else if realcompare(x, 0.0) < 0 && realcompare(y, 0.0) >= 0 {
        2
    } else if realcompare(x, 0.0) < 0 && realcompare(y, 0.0) < 0 {
        3
    } else {
        4
    }
}

fn distance_to_line(p: (f64, f64), p1: (f64, f64), p2: (f64, f64)) -> f64 {
    if realcompare(p1.0, p2.0) == 0 && realcompare(p1.1, p2.1) == 0 {
        distance(p.0, p.1, p1.0, p1.1)
    } else {
        let num = ((p2.1 - p1.1) * p.0 - (p2.0 - p1.0) * p.1 + p2.0 * p1.1 - p2.1 * p1.0).abs();
        let denom = distance(p1.0, p1.1, p2.0, p2.1);
        num / denom
    }
}

fn lic1(x: &[f64], y: &[f64], numpoints: usize, length1: f64) -> bool {
    for i in 0..numpoints - 1 {
        if realcompare(distance(x[i], y[i], x[i + 1], y[i + 1]), length1) > 0 {
            return true;
        }
    }
    false
}

fn lic2(x: &[f64], y: &[f64], numpoints: usize, radius1: f64) -> bool {
    for i in 0..numpoints - 2 {
        if let Some(r) = radius_of_three_points((x[i], y[i]), (x[i + 1], y[i + 1]), (x[i + 2], y[i + 2])) {
            if realcompare(r, radius1) > 0 {
                return true;
            }
        }
    }
    false
}

fn lic3(x: &[f64], y: &[f64], numpoints: usize, epsilon: f64) -> bool {
    for i in 0..numpoints - 2 {
        if let Some(angle) = angle_at_vertex((x[i], y[i]), (x[i + 1], y[i + 1]), (x[i + 2], y[i + 2])) {
            if realcompare(angle, PI - epsilon) < 0 || realcompare(angle, PI + epsilon) > 0 {
                return true;
            }
        }
    }
    false
}

fn lic4(x: &[f64], y: &[f64], numpoints: usize, area1: f64) -> bool {
    for i in 0..numpoints - 2 {
        let area = triangle_area((x[i], y[i]), (x[i + 1], y[i + 1]), (x[i + 2], y[i + 2]));
        if realcompare(area, area1) > 0 {
            return true;
        }
    }
    false
}

fn lic5(x: &[f64], y: &[f64], numpoints: usize, q_pts: usize, quads: usize) -> bool {
    for i in 0..=numpoints - q_pts {
        let mut quad_set = std::collections::HashSet::new();
        for j in i..i + q_pts {
            let q = get_quadrant(x[j], y[j]);
            quad_set.insert(q);
        }
        if quad_set.len() > quads {
            return true;
        }
    }
    false
}

fn lic6(x: &[f64], y: &[f64], numpoints: usize) -> bool {
    for i in 0..numpoints - 1 {
        if realcompare(x[i + 1] - x[i], 0.0) < 0 {
            return true;
        }
    }
    false
}

fn lic7(x: &[f64], y: &[f64], numpoints: usize, n_pts: usize, dist: f64) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..=numpoints - n_pts {
        let start = (x[i], y[i]);
        let end = (x[i + n_pts - 1], y[i + n_pts - 1]);
        for j in i + 1..i + n_pts - 1 {
            let d = distance_to_line((x[j], y[j]), start, end);
            if realcompare(d, dist) > 0 {
                return true;
            }
        }
    }
    false
}

fn lic8(x: &[f64], y: &[f64], numpoints: usize, k_pts: usize, length1: f64) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - k_pts - 1 {
        let j = i + k_pts + 1;
        if realcompare(distance(x[i], y[i], x[j], y[j]), length1) > 0 {
            return true;
        }
    }
    false
}

fn lic9(x: &[f64], y: &[f64], numpoints: usize, a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints - a_pts - b_pts - 2 {
        let j = i + a_pts + 1;
        let k = i + a_pts + b_pts + 2;
        if let Some(r) = radius_of_three_points((x[i], y[i]), (x[j], y[j]), (x[k], y[k])) {
            if realcompare(r, radius1) > 0 {
                return true;
            }
        }
    }
    false
}

fn lic10(x: &[f64], y: &[f64], numpoints: usize, c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints - c_pts - d_pts - 2 {
        let j = i + c_pts + 1;
        let k = i + c_pts + d_pts + 2;
        if let Some(angle) = angle_at_vertex((x[i], y[i]), (x[j], y[j]), (x[k], y[k])) {
            if realcompare(angle, PI - epsilon) < 0 || realcompare(angle, PI + epsilon) > 0 {
                return true;
            }
        }
    }
    false
}

fn lic11(x: &[f64], y: &[f64], numpoints: usize, e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints - e_pts - f_pts - 2 {
        let j = i + e_pts + 1;
        let k = i + e_pts + f_pts + 2;
        let area = triangle_area((x[i], y[i]), (x[j], y[j]), (x[k], y[k]));
        if realcompare(area, area1) > 0 {
            return true;
        }
    }
    false
}

fn lic12(x: &[f64], y: &[f64], numpoints: usize, g_pts: usize) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - g_pts - 1 {
        let j = i + g_pts + 1;
        if realcompare(x[j] - x[i], 0.0) < 0 {
            return true;
        }
    }
    false
}

fn lic13(x: &[f64], y: &[f64], numpoints: usize, k_pts: usize, length1: f64, length2: f64) -> bool {
    if numpoints < 3 {
        return false;
    }
    let mut found_greater = false;
    let mut found_less = false;
    for i in 0..numpoints - k_pts - 1 {
        let j = i + k_pts + 1;
        let d = distance(x[i], y[i], x[j], y[j]);
        if realcompare(d, length1) > 0 {
            found_greater = true;
        }
        if realcompare(d, length2) < 0 {
            found_less = true;
        }
    }
    found_greater && found_less
}

fn lic14(x: &[f64], y: &[f64], numpoints: usize, a_pts: usize, b_pts: usize, radius1: f64, radius2: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    let mut found_greater = false;
    let mut found_less = false;
    for i in 0..numpoints - a_pts - b_pts - 2 {
        let j = i + a_pts + 1;
        let k = i + a_pts + b_pts + 2;
        if let Some(r) = radius_of_three_points((x[i], y[i]), (x[j], y[j]), (x[k], y[k])) {
            if realcompare(r, radius1) > 0 {
                found_greater = true;
            }
            if realcompare(r, radius2) < 0 {
                found_less = true;
            }
        }
    }
    found_greater && found_less
}

fn lic15(x: &[f64], y: &[f64], numpoints: usize, e_pts: usize, f_pts: usize, area1: f64, area2: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    let mut found_greater = false;
    let mut found_less = false;
    for i in 0..numpoints - e_pts - f_pts - 2 {
        let j = i + e_pts + 1;
        let k = i + e_pts + f_pts + 2;
        let area = triangle_area((x[i], y[i]), (x[j], y[j]), (x[k], y[k]));
        if realcompare(area, area1) > 0 {
            found_greater = true;
        }
        if realcompare(area, area2) < 0 {
            found_less = true;
        }
    }
    found_greater && found_less
}

fn compute_cmv(x: &[f64], y: &[f64], numpoints: usize, params: &Parameters) -> Vec<bool> {
    vec![
        lic1(x, y, numpoints, params.length1),
        lic2(x, y, numpoints, params.radius1),
        lic3(x, y, numpoints, params.epsilon),
        lic4(x, y, numpoints, params.area1),
        lic5(x, y, numpoints, params.q_pts, params.quads),
        lic6(x, y, numpoints),
        lic7(x, y, numpoints, params.n_pts, params.dist),
        lic8(x, y, numpoints, params.k_pts, params.length1),
        lic9(x, y, numpoints, params.a_pts, params.b_pts, params.radius1),
        lic10(x, y, numpoints, params.c_pts, params.d_pts, params.epsilon),
        lic11(x, y, numpoints, params.e_pts, params.f_pts, params.area1),
        lic12(x, y, numpoints, params.g_pts),
        lic13(x, y, numpoints, params.k_pts, params.length1, params.length2),
        lic14(x, y, numpoints, params.a_pts, params.b_pts, params.radius1, params.radius2),
        lic15(x, y, numpoints, params.e_pts, params.f_pts, params.area1, params.area2),
    ]
}

fn compute_pum(cmv: &[bool], lcm: &[Vec<String>], pum_diag: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = pum_diag[i];
        for j in 0..15 {
            if i != j {
                let connector = &lcm[i][j];
                pum[i][j] = match connector.as_str() {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => false,
                };
            }
        }
    }
    pum
}

fn compute_fuv(pum: &[Vec<bool>]) -> Vec<bool> {
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }
    fuv
}

fn compute_launch(fuv: &[bool]) -> bool {
    fuv.iter().all(|&x| x)
}

fn decide(input: &Input) -> Output {
    let cmv = compute_cmv(&input.x, &input.y, input.numpoints, &input.parameters);
    let pum = compute_pum(&cmv, &input.lcm, &input.pum_diag);
    let fuv = compute_fuv(&pum);
    let launch = compute_launch(&fuv);
    Output { cmv, pum, fuv, launch }
}

fn main() {
    let mut buffer = String::new();
    io::stdin().read_to_string(&mut buffer).expect("Failed to read input");
    let input: Input = serde_json::from_str(&buffer).expect("Failed to parse JSON");
    let output = decide(&input);
    let json_output = serde_json::to_string(&output).expect("Failed to serialize output");
    println!("{}", json_output);
}
